//\n//  ContentView.swift\n//  DeviceRadar\n//\n//  Created by DeviceRadar Team.\n//  Copyright © 2026 LethalLethes. All rights reserved.\n//\n\nimport SwiftUI\n\n/// Root view of the DeviceRadar app.\n///\n/// Manages the main UI layout:\n/// - Navigation header with refresh button\n/// - Loading state\n/// - List of signals\nstruct ContentView: View {\n    @StateObject private var viewModel = RadarViewModel()\n    \n    var body: some View {\n        NavigationView {\n            ZStack {\n                Color(uiColor: .systemGroupedBackground)\n                    .ignoresSafeArea()\n                \n                if viewModel.isLoading && viewModel.categories.isEmpty {\n                    LoadingView()\n                } else {\n                    MainListView(viewModel: viewModel)\n                }\n                \n                // Error overlay\n                if let error = viewModel.errorMessage {\n                    VStack {\n                        Spacer()\n                        ErrorBannerView(message: error)\n                            .padding()\n                    }\n                }\n            }\n            .navigationTitle(\"DeviceRadar\")\n            .navigationBarTitleDisplayMode(.large)\n            .toolbar {\n                ToolbarItem(placement: .navigationBarTrailing) {\n                    Button(action: { viewModel.generate() }) {\n                        Image(systemName: \"arrow.clockwise\")\n                            .fontWeight(.semibold)\n                    }\n                    .disabled(viewModel.isLoading)\n                }\n            }\n        }\n        .onAppear {\n            viewModel.generate()\n        }\n    }\n}\n\n// MARK: - Preview\n\n#if DEBUG\nstruct ContentView_Previews: PreviewProvider {\n    static var previews: some View {\n        ContentView()\n    }\n}\n#endif\n